var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"누, 누구야? 당신은……?","JPN":"あ、あなたは誰……？","ENG":"What? Who are you?","TWN":"你…你…是誰…？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님!","JPN":"メイド長！","ENG":"Chief Maid!","TWN":"女僕長！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오! 베로니카 양! 마침 좋은 시기에 와 줬구만!","JPN":"おお！　ベロニカ！　ちょうどいいタイミングで来てくれたな！","ENG":"Oh, Veronica! You came right in time!","TWN":"哦！貝洛妮卡！你來得正好！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스를 이용해 주셔서 감사합니다, 주인님.","JPN":"フローラメイドサービスをご利用いただきありがとうございます、ご主人様。","ENG":"Thank you for calling the Flora Maid Service, Master.","TWN":"謝謝您使用芙蘿拉女僕服務，主人。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"예거 님께 말씀을 전해 듣고 기쁜 마음으로 도착했습니다.","JPN":"イェーガー様からお話を伺って、喜んで参りました。","ENG":"Ms. Jaegar said you wanted me, so I came with a glad heart.","TWN":"聽完伊格的話後，就帶著愉悅的心情來找大家囉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥……. 귀띔이나 해 줄 것이지. 메이드장이 올 줄 알았으면 적당히 싸웠을 텐데.","JPN":"ふん……先に教えてくれればよかったのに。メイド長が来ると分かっていたなら適当に戦ってたわ。","ENG":"Hmpf... Why didn’t he tell us earlier? If I knew the Chief Maid was coming, I wouldn't have exerted myself.","TWN":"哼…好歹也要先通知一下吧！早知道女僕長會來，我就不用打得那麼認真啦。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"주인님의 결정에 토를 다는 건 메이드답지 못한 행동이에요. 리코리스.","JPN":"ご主人様の決断に文句を言うのはメイドらしくない行動ですよ、リコリス。","ENG":"Don’t question the Master, Lycoris. It’s not proper for a maid.","TWN":"莉克麗絲，對主人的決定吐槽，不是女僕該有的行爲。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"선배님들도 무사하셨슴까! 나쁜 언니가 나타나서 무지 걱정했지 말임다!","JPN":"先輩たちも無事だったんっすね！　悪いお姉さんが現れてすごく心配したんっすよ！","ENG":"Are you okay, ma’ams? I was very worried about you when the mean lady came here!","TWN":"前輩們都沒事吧？我很擔心壞姊姊會不會傷害大家呢！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야, 야! 끌어안지 마! 다 쳐다 보잖아?!","JPN":"ちょっと！　抱きつかないで！　みんな見てるんだから！","ENG":"No, no, don’t hug me! Everyone’s looking at us!","TWN":"喂！不要抱我啦！大家都在看我們欸？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"보아하니 그쪽 언니가 쟤들이 믿는 구석인가 보지?","JPN":"どうやらそっちの姉ちゃんが隠し球みたいだな？","ENG":"So, you are the one they were waiting for?","TWN":"看來這位姊姊應該是他們的靠山吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"카운터도 아닌 것 같은데 기습 한 번 성공했다고 너무 뻐기는 거 아냐?","JPN":"カウンターでもないくせに、たった1回の奇襲に成功したからって調子乗るんじゃねえぞ。","ENG":"You don’t look like a Counter. Don’t get cocky because of this one-time success.","TWN":"我看你好像也不是制裁者，不過就成功突襲一次，還以為自己真的很行嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"말씀하신 대로, 카운터는 분명 일반인에 비해 월등히 강인합니다.","JPN":"おっしゃるとおり、カウンターは一般人に比べてはるかに強いでしょう。","ENG":"Like you said, Counters are far stronger than ordinary people.","TWN":"正如你所說，制裁者肯定比一般人強。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그러니 정말 다행이에요.","JPN":"ですので、本当に幸いです。","ENG":"That’s why I’m grateful.","TWN":"所以真是太好了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님을 업신여긴 분께는, 손대중에 실수할지도 모를 일이니까요.","JPN":"ご主人様を見下した方は、手加減するつもりがミスをしてしまうかもしれませんので。","ENG":"I can punish you for insulting my master without holding back.","TWN":"那對於欺負主人的人，我也就不需要手下留情囉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스의 이름을 걸고 손님을 응대해 드리겠습니다.","JPN":"フローラメイドサービスの名にかけて、お客様をおもてなしいたします。","ENG":"Let me welcome you in the name of the Flora Maid Service.","TWN":"我會以芙蘿拉女僕服務公司的名義招待您。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"두 번 다시 잊지 못할 만큼, 정중하고 극진하게.","JPN":"二度と忘れられないぐらい丁寧に、そして手厚く。","ENG":"It will be the most polite and cordial welcoming ceremony.","TWN":"竭誠地讓您永生難忘。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};